export function nextGeneration(liveCells: Cell[]): Cell[] {
  const live = new Set(liveCells.map(cellKey));

  const neighborhoods = liveCells.flatMap(([x, y]) =>
    NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy])
  );

  const candidates = new Map<string, Cell>(
    neighborhoods.map((cell) => [cellKey(cell), cell])
  );

  const neighborCount = (k: string): number =>
    neighborhoods.filter((cell) => cellKey(cell) === k).length;

  const survives = (k: string): boolean => {
    const count = neighborCount(k);
    return count === 3 || (count === 2 && live.has(k));
  };

  return [...candidates]
    .filter(([k]) => survives(k))
    .map(([, cell]) => cell);
}

