export function nextGeneration(liveCells: Cell[]): Cell[] {
  const live = new Set(liveCells.map(cellKey));

  const neighbors: Cell[] = liveCells.flatMap(([x, y]) =>
    NEIGHBOR_OFFSETS.map(([dx, dy]): Cell => [x + dx, y + dy])
  );

  const counts = new Map<string, number>();
  const candidates = new Map<string, Cell>();
  for (const cell of neighbors) {
    const k = cellKey(cell);
    counts.set(k, (counts.get(k) ?? 0) + 1);
    candidates.set(k, cell);
  }

  const survives = (k: string, count: number): boolean =>
    count === 3 || (count === 2 && live.has(k));

  return [...candidates]
    .filter(([k]) => survives(k, counts.get(k) ?? 0))
    .map(([, cell]) => cell);
}
